<template>
  <div class="root">
    <div class="main-container">
      <NativeToolBar
        @tool-change="handleToolChange"
        @line-width-change="handleLineWidthChange"
        @stroke-style-change="handleStrokeStyleChange"
        @fill-style-change="handleFillStyleChange"
      />
      <NativeCanvas
        ref="canvas"
      />
    </div>
  </div>
</template>

<script>
import NativeToolBar from '../components/native-drawing/NativeToolBar.vue'
import NativeCanvas from '../components/native-drawing/NativeCanvas.vue'

export default {
  name: 'NativeKonva',
  components: {
    NativeToolBar,
    NativeCanvas
  },
  methods: {
    handleToolChange(toolId) {
      if (this.$refs.canvas) {
        this.$refs.canvas.currentTool = toolId
      }
    },
    handleLineWidthChange(lineWidth) {
      if (this.$refs.canvas) {
        this.$refs.canvas.lineWidth = lineWidth
      }
    },
    handleStrokeStyleChange(strokeStyle) {
      if (this.$refs.canvas) {
        this.$refs.canvas.strokeStyle = strokeStyle
      }
    },
    handleFillStyleChange(fillStyle) {
      if (this.$refs.canvas) {
        this.$refs.canvas.fillStyle = fillStyle
      }
    }
  }
}
</script>

<style lang="less" scoped>
.root {
  height: 100%;
  display: flex;
  flex-direction: column;
}

.main-container {
  display: flex;
  flex: 1;
  width: 100%;
  height: 100%;
  overflow: hidden;
}
</style>