<template>
  <div class="native-canvas-container" ref="container">
    <canvas ref="canvas" @mousedown="handleMouseDown" @mousemove="handleMouseMove" @mouseup="handleMouseUp" @wheel="handleWheel"></canvas>
    <div class="canvas-controls">
      <button @click="resetViewport" class="control-btn">重置视图</button>
      <div class="zoom-info">{{ Math.round(scale * 100) }}%</div>
    </div>
    <div class="coordinate-info">
      X: {{ Math.round(mousePosition.x) }}, Y: {{ Math.round(mousePosition.y) }}
    </div>
  </div>
</template>

<script>
export default {
  name: 'NativeCanvas',
  data() {
    return {
      isDrawing: false,
      scale: 1,
      viewportPosition: { x: 0, y: 0 },
      mousePosition: { x: 0, y: 0 },
      startPos: { x: 0, y: 0 },
      currentShape: null,
      shapes: [],
      currentTool: 'rect',
      strokeStyle: '#000000',
      fillStyle: '#ffffff',
      lineWidth: 2
    }
  },
  mounted() {
    this.initCanvas()
    window.addEventListener('resize', this.handleResize)
  },
  beforeDestroy() {
    window.removeEventListener('resize', this.handleResize)
  },
  methods: {
    initCanvas() {
      const container = this.$refs.container
      const canvas = this.$refs.canvas
      
      canvas.width = container.clientWidth
      canvas.height = container.clientHeight
      
      this.drawGrid()
      this.drawShapes()
    },
    handleResize() {
      this.initCanvas()
    },
    drawGrid() {
      const canvas = this.$refs.canvas
      const ctx = canvas.getContext('2d')
      const width = canvas.width
      const height = canvas.height
      const gridSize = 20
      
      ctx.save()
      ctx.translate(this.viewportPosition.x, this.viewportPosition.y)
      ctx.scale(this.scale, this.scale)
      
      ctx.strokeStyle = '#e0e0e0'
      ctx.lineWidth = 1
      
      // 绘制垂直线
      for (let x = 0; x < width / this.scale; x += gridSize) {
        ctx.beginPath()
        ctx.moveTo(x, 0)
        ctx.lineTo(x, height / this.scale)
        ctx.stroke()
      }
      
      // 绘制水平线
      for (let y = 0; y < height / this.scale; y += gridSize) {
        ctx.beginPath()
        ctx.moveTo(0, y)
        ctx.lineTo(width / this.scale, y)
        ctx.stroke()
      }
      
      ctx.restore()
    },
    drawShapes() {
      const canvas = this.$refs.canvas
      const ctx = canvas.getContext('2d')
      
      ctx.clearRect(0, 0, canvas.width, canvas.height)
      this.drawGrid()
      
      ctx.save()
      ctx.translate(this.viewportPosition.x, this.viewportPosition.y)
      ctx.scale(this.scale, this.scale)
      
      this.shapes.forEach(shape => {
        this.drawShape(ctx, shape)
      })
      
      if (this.currentShape) {
        this.drawShape(ctx, this.currentShape)
      }
      
      ctx.restore()
    },
    drawShape(ctx, shape) {
      ctx.strokeStyle = shape.strokeStyle
      ctx.fillStyle = shape.fillStyle
      ctx.lineWidth = shape.lineWidth
      
      ctx.beginPath()
      
      switch (shape.type) {
        case 'rect':
          const rectX = Math.min(shape.startX, shape.endX)
          const rectY = Math.min(shape.startY, shape.endY)
          const rectWidth = Math.abs(shape.endX - shape.startX)
          const rectHeight = Math.abs(shape.endY - shape.startY)
          ctx.rect(rectX, rectY, rectWidth, rectHeight)
          break
        case 'circle':
          const circleRadius = Math.sqrt(
            Math.pow(shape.endX - shape.startX, 2) + 
            Math.pow(shape.endY - shape.startY, 2)
          )
          ctx.arc(shape.startX, shape.startY, circleRadius, 0, Math.PI * 2)
          break
        case 'line':
          ctx.moveTo(shape.startX, shape.startY)
          ctx.lineTo(shape.endX, shape.endY)
          break
        case 'path':
          if (shape.points.length >= 2) {
            ctx.moveTo(shape.points[0], shape.points[1])
            for (let i = 2; i < shape.points.length; i += 2) {
              ctx.lineTo(shape.points[i], shape.points[i + 1])
            }
            if (shape.closed) {
              ctx.closePath()
            }
          }
          break
      }
      
      if (shape.type !== 'line') {
        ctx.fill()
      }
      ctx.stroke()
    },
    handleMouseDown(e) {
      const canvas = this.$refs.canvas
      const rect = canvas.getBoundingClientRect()
      const mouseX = (e.clientX - rect.left - this.viewportPosition.x) / this.scale
      const mouseY = (e.clientY - rect.top - this.viewportPosition.y) / this.scale
      
      this.isDrawing = true
      this.startPos = { x: mouseX, y: mouseY }
      
      switch (this.currentTool) {
        case 'rect':
        case 'circle':
        case 'line':
          this.currentShape = {
            type: this.currentTool,
            startX: mouseX,
            startY: mouseY,
            endX: mouseX,
            endY: mouseY,
            strokeStyle: this.strokeStyle,
            fillStyle: this.fillStyle,
            lineWidth: this.lineWidth
          }
          break
        case 'path':
          this.currentShape = {
            type: 'path',
            points: [mouseX, mouseY],
            closed: false,
            strokeStyle: this.strokeStyle,
            fillStyle: this.fillStyle,
            lineWidth: this.lineWidth
          }
          break
      }
    },
    handleMouseMove(e) {
      const canvas = this.$refs.canvas
      const rect = canvas.getBoundingClientRect()
      const mouseX = (e.clientX - rect.left - this.viewportPosition.x) / this.scale
      const mouseY = (e.clientY - rect.top - this.viewportPosition.y) / this.scale
      
      this.mousePosition = { x: mouseX, y: mouseY }
      
      if (this.isDrawing && this.currentShape) {
        switch (this.currentTool) {
          case 'rect':
          case 'circle':
          case 'line':
            this.currentShape.endX = mouseX
            this.currentShape.endY = mouseY
            break
          case 'path':
            this.currentShape.points.push(mouseX, mouseY)
            break
        }
        this.drawShapes()
      }
    },
    handleMouseUp() {
      if (this.isDrawing && this.currentShape) {
        this.shapes.push(this.currentShape)
        this.currentShape = null
        this.isDrawing = false
        this.drawShapes()
      }
    },
    handleWheel(e) {
      e.preventDefault()
      const delta = e.deltaY > 0 ? -0.1 : 0.1
      const newScale = Math.max(0.1, Math.min(5, this.scale * (1 + delta)))
      
      if (newScale !== this.scale) {
        const canvas = this.$refs.canvas
        const rect = canvas.getBoundingClientRect()
        const mouseX = e.clientX - rect.left
        const mouseY = e.clientY - rect.top
        
        const oldScale = this.scale
        this.scale = newScale
        
        // 调整视口位置，使鼠标位置保持不变
        this.viewportPosition.x = mouseX - (mouseX - this.viewportPosition.x) * (newScale / oldScale)
        this.viewportPosition.y = mouseY - (mouseY - this.viewportPosition.y) * (newScale / oldScale)
        
        this.drawShapes()
      }
    },
    resetViewport() {
      this.scale = 1
      this.viewportPosition = { x: 0, y: 0 }
      this.drawShapes()
    }
  }
}
</script>

