<template>
  <div class="native-toolbar">
    <div class="toolbar-header">
      <h3>绘图工具</h3>
    </div>
    <div class="toolbar-content">
      <div class="tool-group">
        <button 
          v-for="tool in tools" 
          :key="tool.id"
          :class="['tool-btn', { active: currentTool === tool.id }]"
          @click="selectTool(tool.id)"
          :title="tool.name"
        >
          <span class="tool-icon">{{ tool.icon }}</span>
          <span class="tool-name">{{ tool.name }}</span>
        </button>
      </div>
      <div class="tool-group">
        <div class="tool-property">
          <label>线条宽度</label>
          <input 
            type="range" 
            min="1" 
            max="10" 
            v-model.number="lineWidth"
            @change="updateLineWidth"
          >
          <span>{{ lineWidth }}px</span>
        </div>
        <div class="tool-property">
          <label>描边颜色</label>
          <input 
            type="color" 
            v-model="strokeStyle"
            @change="updateStrokeStyle"
          >
        </div>
        <div class="tool-property">
          <label>填充颜色</label>
          <input 
            type="color" 
            v-model="fillStyle"
            @change="updateFillStyle"
          >
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'NativeToolBar',
  data() {
    return {
      currentTool: 'rect',
      lineWidth: 2,
      strokeStyle: '#000000',
      fillStyle: '#ffffff',
      tools: [
        { id: 'rect', name: '矩形', icon: '⬜' },
        { id: 'circle', name: '圆形', icon: '⭕' },
        { id: 'line', name: '直线', icon: '—' },
        { id: 'path', name: '路径', icon: '✏️' }
      ]
    }
  },
  methods: {
    selectTool(toolId) {
      this.currentTool = toolId
      this.$emit('tool-change', toolId)
    },
    updateLineWidth() {
      this.$emit('line-width-change', this.lineWidth)
    },
    updateStrokeStyle() {
      this.$emit('stroke-style-change', this.strokeStyle)
    },
    updateFillStyle() {
      this.$emit('fill-style-change', this.fillStyle)
    }
  }
}
</script>

